from __future__ import annotations

import argparse
import hashlib
import subprocess
import sys
from datetime import datetime, timezone
from pathlib import Path
from typing import TYPE_CHECKING

import defusedxml.ElementTree as ET

from dissect.target.tools.utils.cli import catch_sigpipe

if TYPE_CHECKING:
    from collections.abc import Iterator
    from xml.etree.ElementTree import Element


TEMPLATE = """\
# This file is generated by target-build-magic
# Do not edit manually, for overrides see 'overrides.py'
#
# Generated on:         {timestamp}
# Source SHA1 hash:     {hash}
# Number of types:      {count}
# References:           http://www.freedesktop.org/standards/shared-mime-info
#                       https://gitlab.freedesktop.org/xdg/shared-mime-info/-/blob/master/data/freedesktop.org.xml.in
from __future__ import annotations

TYPES = {types}
"""

IGNORED_TYPES = (
    # Conflicts with ELF
    "application/x-iso9660-appimage",
    "application/vnd.appimage",
    "application/x-core",
    # Conflicts with application/zip
    "application/x-karbon",
    "application/x-kchart",
    "application/x-kformula",
    "application/x-kivio",
    "application/x-kontour",
    "application/x-kpresenter",
    "application/x-krita",
    "application/x-kspread",
    "application/x-kword",
    # Conflicts with TIFF
    "image/x-3ds",
    # Conflicts with TAR
    "text/x-devicetree-source",
    # Conflicts with DEB
    "application/x-archive",
    # Conflicts with XML
    "application/x-quicktime-media-link",
    # Conflicts with OGG
    "application/annodex",
    # Conflicts with ZLIB
    "text/x-todo-txt",
    # Conflicts with PNG
    "image/apng",
    # Too broad definition
    "video/mp2t",
)

IGNORED_SUB_TYPES = (
    "application/zip",
    "application/xml",
    "application/json",
    "application/annodex",
    "application/x-msdownload",
)

PREFER_ALIAS = {
    # Override for sane MZ name
    "application/x-msdownload": "application/x-ms-dos-executable",
}


def parse_freedesktop_xml(path: Path) -> str:
    """Attempt to parse a FreeDesktop shared-mime-info document."""
    ns = {"mime": "http://www.freedesktop.org/standards/shared-mime-info"}
    types = []

    content = path.read_bytes()
    hash = hashlib.sha1(content).hexdigest()

    magics_seen = set()

    for mime_type in ET.fromstring(content.decode()).findall("mime:mime-type", ns):
        mime_type_name = mime_type.get("type")

        # Ignore certain (sub) types if they are conflicting with other types.
        sub_class = mime_type.find("mime:sub-class-of", ns)
        if mime_type_name in IGNORED_TYPES or (sub_class is not None and sub_class.get("type") in IGNORED_SUB_TYPES):
            continue

        # Iterate over all 'main' magic match definitions in this mime type node.
        magics = []
        for magic_match in mime_type.findall("mime:magic/mime:match", ns):
            for offset, value in parse_magic_match(magic_match):
                # We do not allow duplicate magic values with the same offset.
                if (offset, value) in magics_seen:
                    print(f"Duplicate magic value for type {mime_type_name!r}: offset={offset!r} value={value!r}")
                    continue

                # Ignore too short magic values to prevent false positives.
                if len(value) < 2:
                    print(
                        f"Magic value too short to be usable for type {mime_type_name!r}: offset={offset!r} value={value!r}"  # noqa: E501
                    )
                    continue

                magics_seen.add((offset, value))
                magics.append({"offset": offset, "value": value})

        # Iterate over all file suffix patterns in this mime type node.
        patterns = [g.get("pattern") for g in mime_type.findall("mime:glob", ns)]
        if not patterns and not magics:
            print(f"No usable definitions for {mime_type_name!r}")
            continue

        aliases = [alias.attrib.get("type") for alias in mime_type.iterfind("mime:alias", ns)]
        if (override := PREFER_ALIAS.get(mime_type_name)) and override in aliases:
            mime_type_name = override

        type_obj = {
            "type": mime_type_name,
            "name": mime_type.find("mime:comment", ns).text,
            "pattern": patterns,
            "magic": magics,
        }
        types.append(type_obj)

    print(f"Parsed {len(types)} types")

    return TEMPLATE.format(timestamp=datetime.now(tz=timezone.utc), count=len(types), hash=hash, types=types)


def parse_magic_match(
    magic_match: Element, first_offset: int | None = None, prev_value: bytes | None = None
) -> Iterator[tuple[int, bytes]] | None:
    """Parse (nested) magic match element(s) to a tuple of offset and magic bytes.

    Does not (yet) support nested magic match objects with gaps. Only succesive magic definitions are stitched together.
    """
    value = magic_match.get("value")
    type = magic_match.get("type")

    # Throw value errors if the XML document is invalid according to the spec.
    if not value:
        raise ValueError(f"Missing value in {magic_match!r}")
    if not type:
        raise ValueError(f"Missing type in {magic_match!r}")

    # Print a warning if this magic definition value could not be parsed by us.
    try:
        value = convert_value(type, value)
    except Exception as e:
        print(f"Failed to convert {type!r} with value {value!r}: {e!s}")
        # If we have a parent, yield that instead.
        if prev_value:
            yield first_offset, prev_value
        return None

    # Calculate the offset - which is always absolute and never relative!
    if ":" in (offset := magic_match.get("offset", "0")):
        offset = offset.split(":")[0]
    try:
        offset = int(offset)
    except ValueError:
        pass

    # Some nested magic definitions have a gap, e.g. `offset=0,value=0x01` -> `offset=4,value=0x02`.
    # We do not support these definitions yet, so instead we return a less precise definition of the parent.
    if prev_value and (offset > (first_offset + len(prev_value)) or offset <= first_offset):
        yield first_offset, prev_value
        return

    # Iterate the *direct* children of this element.
    if children := list(magic_match):
        for child in children:
            yield from parse_magic_match(
                child,
                first_offset=offset if first_offset is None else first_offset,
                prev_value=prev_value + value if prev_value else value,
            )

    # Only emit the offset and value if there are no children for this element.
    else:
        offset = offset - len(prev_value) if prev_value else offset
        value = prev_value + value if prev_value else value
        # Some bugs exist in the XML...
        if offset < 0:
            return
        yield offset, value


def convert_value(type: str, value: str) -> bytes:
    """Convert a value to bytes."""
    # Regular string conversion to bytes
    # e.g. "PK\\003\\004"       -> b"PK\x03\x04"
    # e.g. "\\x00\\x01"         -> b"\x00\x01"
    # e.g. "\x89PNG\r\n\x1A\n"  -> b"\x89PNG\r\n\x1a\n"
    if type == "string":
        if "\\x" in value or "\\0" in value:
            return value.encode("latin1").decode("unicode-escape").encode("latin1")
        return value.encode("latin1")

    # Integer conversion
    # e.g. "0x9501"     -> b"\x95\x01"
    # e.g. "0xa1b2c3d4" -> b"\xa1\xb2\xc3\xd4"
    if type in ("byte", "little16", "little32", "big16", "big32", "host16", "host32"):
        return bytes.fromhex(value[2:] if value[:2] == "0x" else value)

    raise ValueError(f"Unknown type {type!r}")


@catch_sigpipe
def main() -> int:
    help_formatter = argparse.ArgumentDefaultsHelpFormatter
    parser = argparse.ArgumentParser(
        description="target-build-magic",
        fromfile_prefix_chars="@",
        formatter_class=help_formatter,
    )
    parser.add_argument("path", metavar="PATH", type=Path, help="path to freedesktop.org.xml.in file")
    parser.add_argument(
        "--output", "-o", type=Path, help="optional alternative output path for generated types document"
    )
    parser.add_argument("--format", action="store_true", default=False, help="format output using ruff")
    args = parser.parse_args()

    if not args.path.is_file():
        print(f"Provided file does not exist: {args.path}")
        return 1

    output = (args.output or Path(__file__).parents[1].joinpath("helpers/magic/mimetypes/freedesktop.py")).resolve()

    if not output.parent.is_dir():
        print(f"Output path parent directory {output.parent} does not exist")
        return 1

    try:
        content = parse_freedesktop_xml(args.path)
    except Exception as e:
        print(f"Exception while generating output: {e!s}")
        return 1

    try:
        output.write_text(content)
    except Exception as e:
        print(f"Exception while writing output to {output!s}: {e!s}")
        return 1

    if args.format:
        subprocess.run(["ruff", "format", output], capture_output=True)
        subprocess.run(["ruff", "check", "--fix", "--unsafe-fixes", output], capture_output=True)

    return 0


if __name__ == "__main__":
    sys.exit(main())
